/**
 * Self-contained triangulation dimensional coercion tests.
 *
 * Run:
 *   pnpm run gnode -- run open-source/gnosis/src/__tests__/triangulation-dimensional-coercion.test.ts
 */

import assert from 'node:assert';
import { scanReductionProjections } from '../spiderweb-topology';
import {
  buildTriangulationCoercionMatrix,
  coerceAcrossDimensions,
  coercionMatrixToReductionInputs,
  eulerTwo,
  unknotDebtAfterCoercion,
  unknotDebtDrop,
  unknotDebtToTarget,
  roundTripAcrossDimensions,
  simplexMass,
  sphereToTriangulation,
  triangulationToSphere,
} from '../triangulation-dimensional-coercion';

const octahedron = {
  vertices: 6,
  edges: 12,
  faces: 8,
} as const;

assert.strictEqual(eulerTwo(octahedron), true);
assert.strictEqual(simplexMass(octahedron), 26);

const lifted = coerceAcrossDimensions(octahedron, 2, 54);
assert.strictEqual(lifted.ambientDim, 54);
assert.deepStrictEqual(lifted.mesh, octahedron);
assert.strictEqual(simplexMass(lifted.mesh), simplexMass(octahedron));
assert.strictEqual(unknotDebtToTarget(2, 54), 52);
assert.strictEqual(unknotDebtAfterCoercion(2, 54), 0);
assert.strictEqual(unknotDebtDrop(2, 54), 52);
assert.strictEqual(unknotDebtToTarget(54, 2), 0);
assert.strictEqual(unknotDebtDrop(54, 2), 0);

const roundTrip = roundTripAcrossDimensions(octahedron, 2, 54);
assert.strictEqual(roundTrip.ambientDim, 2);
assert.deepStrictEqual(roundTrip.mesh, octahedron);

const sphere = triangulationToSphere(octahedron);
assert.deepStrictEqual(sphereToTriangulation(sphere), octahedron);

const matrix = buildTriangulationCoercionMatrix(
  octahedron,
  [2, 3, 6, 54],
  'tri-coerce'
);

assert.deepStrictEqual(matrix.dimensions, [2, 3, 6, 54]);
assert.strictEqual(matrix.edges.length, 12);
assert.ok(matrix.edges.some((edge) => edge.id === 'tri-coerce:2->3'));
assert.ok(matrix.edges.some((edge) => edge.id === 'tri-coerce:54->2'));
assert.ok(matrix.edges.every((edge) => edge.eulerTwoWitnessed));
assert.ok(matrix.edges.every((edge) => edge.preservesMesh));
assert.ok(matrix.edges.every((edge) => edge.preservesSimplexMass));
assert.ok(matrix.edges.every((edge) => edge.roundTripPreservesMesh));
assert.strictEqual(
  matrix.edges.filter((edge) => edge.strictlyReducesUnknotDebt).length,
  6
);
assert.ok(
  matrix.edges
    .filter((edge) => edge.strictlyReducesUnknotDebt)
    .every((edge) => edge.unknotDebtDrop > 0)
);

const reductionInputs = coercionMatrixToReductionInputs(matrix);
assert.strictEqual(reductionInputs.length, 12);

const scans = scanReductionProjections(reductionInputs);
assert.strictEqual(scans.length, 12);
assert.strictEqual(
  scans.filter((scan) => scan.shapeUnit.isProjectionParadox).length,
  6
);
assert.ok(scans.every((scan) => scan.sandwich.withinBounds));
assert.ok(scans.every((scan) => scan.predictive.consistent));

console.log('triangulation-dimensional-coercion: all tests passed');
